def calcular_tiempo_total(datos: list) -> float:    """    Calcula la suma del tiempo a partir de una lista con dicha informacion.    Parametros    ----------    datos (list): lista de numero entero , tiempo    Retorna    ---------      float: La cantidad total de tiempo    """    if datos == []:        return 0    tiempo_total= 0    for dato in datos:        tiempo_total= tiempo_total + dato            return tiempo_totaldef calcular_promedio_uso(datos: list) -> float:    """    Calcula el promedio del tiempo de uso a partir de el calculo de la cantidad y la lista de tiempo total    Parameters    ----------    datos : list        lista de numeros enteros (tiempo)    Returns    -------    float        el promedio total del tiempo    """    if datos == []:        return 0    total= calcular_tiempo_total(datos)     cantidad= 0    for dato in datos:        cantidad += 1    promedio= total /cantidad    return promedio    